/**
 * File service class providing functionality to find files by pattern
 */
public class FileService {

    /**
     * Find files matching the specified pattern
     *
     * @param searchDir   Path of the directory to search
     * @param filePattern Filename pattern (supports wildcards)
     * @return List of found files, one per line; returns error message on failure
     */
    public String findFilesWithPattern(String searchDir, String filePattern) {
        if (searchDir == null || filePattern == null || searchDir.trim().isEmpty()) {
            return "Error: Search directory or file pattern is empty.";
        }

        // Construct shell command
        String cmdStr = String.format("find \"%s\" -type f -name \"%s\" | head -n 10", searchDir, filePattern);
        String[] command = {"/bin/bash", "-c", cmdStr};

        Process process = null;
        ExecutorService executor = null;
        try {
            // Execute command
            process = Runtime.getRuntime().exec(command);

            // Use ExecutorService to read streams concurrently to avoid deadlocks
            executor = Executors.newFixedThreadPool(2);
            Future<String> outputFuture = executor.submit(new StreamReader(process.getInputStream()));
            Future<String> errorFuture = executor.submit(new StreamReader(process.getErrorStream()));

            // Wait for command execution to complete
            int exitCode = process.waitFor();

            // Get the results from the stream readers
            String output = outputFuture.get().trim();
            String error = errorFuture.get().trim();

            // Determine result based on exit code and output
            if (exitCode != 0) {
                // Command execution failed, return error information
                return "Error: File search failed.\n" + (error.isEmpty() ? output : error);
            }

            if (output.isEmpty()) {
                return "No matching files found.";
            }

            return output;
        } catch (IOException e) {
            return "Error: IO exception occurred: " + e.getMessage();
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            return "Error: Operation was interrupted: " + e.getMessage();
        } catch (Exception e) {
            return "Error: Unexpected exception occurred: " + e.getMessage();
        } finally {
            if (executor != null) {
                executor.shutdown();
            }
            if (process != null) {
                // Ensure child process is destroyed
                process.destroy();
            }
        }
    }

    /**
     * Helper class to read input stream and return as string using Callable for concurrency
     */
    private static class StreamReader implements Callable<String> {
        private final InputStream inputStream;

        StreamReader(InputStream inputStream) {
            this.inputStream = inputStream;
        }

        @Override
        public String call() throws IOException {
            StringBuilder result = new StringBuilder();
            try (BufferedReader reader = new BufferedReader(new InputStreamReader(inputStream))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    result.append(line).append("\n");
                }
            }
            return result.toString();
        }
    }
}

